const tagResults = $('Tags holen').first().json.results || [];
const corrResults = $('Korrespondenten holen').first().json.results || [];
const docTypeResults = $('Dokumenttypen holen').first().json.results || [];

const tagMap = {};
for (const t of tagResults) { tagMap[t.name.toLowerCase()] = t.id; }
const notYetTaggedId = tagMap['not-yet-tagged'];
if (!notYetTaggedId) throw new Error('Tag "not-yet-tagged" nicht in Paperless gefunden');

const corrMap = {};
for (const c of corrResults) { corrMap[c.name.toLowerCase()] = c.id; }

const docTypeMap = {};
for (const d of docTypeResults) { docTypeMap[d.name.toLowerCase()] = d.id; }

const docs = $input.first().json.results || [];
if (!docs.length) return [];

return docs.map(doc => ({
  json: {
    docId: doc.id,
    currentTitle: doc.title,
    content: (doc.content || '').slice(0, 6000),
    currentTags: doc.tags.filter(id => id !== notYetTaggedId),
    notYetTaggedId,
    tagMap,
    corrMap,
    docTypeMap
  }
}));

const doc = $('Pro Dokument').item.json;
let raw = $input.item.json.choices?.[0]?.message?.content || '';

raw = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

let title = doc.currentTitle;
let suggestedTags = [];
let correspondentName = null;
let documentTypeName = null;
let created = null;

try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    if (parsed.title) title = parsed.title.trim().slice(0, 80);
    suggestedTags = (parsed.tags || []).map(t => t.toLowerCase().trim().replace(/[^a-z0-9\-äöüß]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, ''));
    if (parsed.correspondent && parsed.correspondent !== 'null') correspondentName = String(parsed.correspondent).trim();
    if (parsed.document_type && parsed.document_type !== 'null') documentTypeName = String(parsed.document_type).trim();
    if (parsed.created && parsed.created !== 'null') {
      const d = new Date(parsed.created);
      if (!isNaN(d.getTime())) created = parsed.created;
    }
  }
} catch(e) {}

const tagMap = doc.tagMap || {};
const corrMap = doc.corrMap || {};
const docTypeMap = doc.docTypeMap || {};

const existingTagIds = [...doc.currentTags];
const newTagNames = [];
for (const name of suggestedTags) {
  if (tagMap[name] !== undefined) {
    if (!existingTagIds.includes(tagMap[name])) existingTagIds.push(tagMap[name]);
  } else {
    newTagNames.push(name);
  }
}

let correspondentId = null;
let newCorrespondentName = null;
if (correspondentName) {
  const key = correspondentName.toLowerCase();
  if (corrMap[key] !== undefined) { correspondentId = corrMap[key]; }
  else { newCorrespondentName = correspondentName; }
}

let documentTypeId = null;
let newDocumentTypeName = null;
if (documentTypeName) {
  const key = documentTypeName.toLowerCase();
  if (docTypeMap[key] !== undefined) { documentTypeId = docTypeMap[key]; }
  else { newDocumentTypeName = documentTypeName; }
}

return [{ json: {
  docId: doc.docId,
  title,
  created,
  existingTagIds,
  newTagNames,
  notYetTaggedId: doc.notYetTaggedId,
  correspondentId,
  newCorrespondentName,
  documentTypeId,
  newDocumentTypeName,
  tagMap,
  corrMap,
  docTypeMap,
  skipTagCreation: newTagNames.length === 0
}}];

const httpResp = $input.item.json;
const parseData = $('Antwort parsen').item.json;

let correspondentId = parseData.correspondentId;
if (httpResp.id) {
  correspondentId = httpResp.id;
} else if (parseData.newCorrespondentName) {
  correspondentId = parseData.corrMap[parseData.newCorrespondentName.toLowerCase()] || null;
}

return [{ json: { ...parseData, correspondentId } }];

const httpResp = $input.item.json;
const corrData = $('Korrespondent-ID ermitteln').item.json;

let documentTypeId = corrData.documentTypeId;
if (httpResp.id) {
  documentTypeId = httpResp.id;
} else if (corrData.newDocumentTypeName) {
  documentTypeId = corrData.docTypeMap[corrData.newDocumentTypeName.toLowerCase()] || null;
}

return [{ json: { ...corrData, documentTypeId } }];

const httpResp = $input.item.json;
const tagItem = $('Tags aufteilen').item.json;

let resolvedTagId = null;
if (httpResp.id) {
  resolvedTagId = httpResp.id;
} else {
  resolvedTagId = (tagItem.tagMap || {})[tagItem.currentTagName] || null;
}
return [{ json: { ...tagItem, resolvedTagId } }];

const items = $input.all();

// Pfad 1: keine neuen Tags nötig
if (items[0]?.json?.skipTagCreation) {
  const d = items[0].json;
  const patch = { docId: d.docId, title: d.title, finalTagIds: d.existingTagIds };
  if (d.correspondentId) patch.correspondentId = d.correspondentId;
  if (d.documentTypeId) patch.documentTypeId = d.documentTypeId;
  if (d.created) patch.created = d.created;
  return [{ json: patch }];
}

// Pfad 2: nach Tag-Erstellung (Items aus inner-loop done)
const base = items[0].json;
const collectedIds = [...base.existingTagIds];
for (const item of items) {
  const id = item.json.resolvedTagId;
  if (id && !collectedIds.includes(id)) collectedIds.push(id);
}
const patch = { docId: base.docId, title: base.title, finalTagIds: collectedIds };
if (base.correspondentId) patch.correspondentId = base.correspondentId;
if (base.documentTypeId) patch.documentTypeId = base.documentTypeId;
if (base.created) patch.created = base.created;
return [{ json: patch }];

const d = $input.item.json;
const body = { title: d.title, tags: d.finalTagIds };
if (d.correspondentId != null) body.correspondent = d.correspondentId;
if (d.documentTypeId != null) body.document_type = d.documentTypeId;
if (d.created) body.created = d.created;
return [{ json: { ...d, patchBody: JSON.stringify(body) } }];
